// Hashi (Bridges) game logic utilities

export const ERROR_NON_ADJACENT = 'Cannot connect non-adjacent islands';
export const ERROR_MAX_2 = 'Max 2 bridges per pair';
export const ERROR_EXCEED = 'Island would exceed its number';
export const ERROR_CROSS = 'Bridges would cross';

export function canonicalBridgeKey(a, b) {
  // a,b are islands with grid coordinates
  const p1 = { x: a.x, y: a.y };
  const p2 = { x: b.x, y: b.y };
  const first = p1.x < p2.x || (p1.x === p2.x && p1.y <= p2.y) ? p1 : p2;
  const second = first === p1 ? p2 : p1;
  return `${first.x},${first.y},${second.x},${second.y}`;
}

function buildCoordMap(islands) {
  const m = new Map();
  for (const isl of islands) m.set(`${isl.x},${isl.y}`, isl);
  return m;
}

export function areAdjacent(islands, a, b) {
  if (!a || !b) return false;
  if (a.id === b.id) return false;
  if (a.x !== b.x && a.y !== b.y) return false;

  const coordMap = buildCoordMap(islands);
  if (a.x === b.x) {
    const x = a.x;
    const [y1, y2] = a.y < b.y ? [a.y, b.y] : [b.y, a.y];
    for (let y = y1 + 1; y <= y2 - 1; y++) {
      if (coordMap.has(`${x},${y}`)) return false;
    }
    return true;
  }

  const y = a.y;
  const [x1, x2] = a.x < b.x ? [a.x, b.x] : [b.x, a.x];
  for (let x = x1 + 1; x <= x2 - 1; x++) {
    if (coordMap.has(`${x},${y}`)) return false;
  }
  return true;
}

function parseKey(key) {
  const [x1, y1, x2, y2] = key.split(',').map((n) => Number(n));
  return { x1, y1, x2, y2 };
}

function isHorizontal(seg) {
  return seg.y1 === seg.y2;
}

function segmentsCross(segA, segB) {
  // Only perpendicular crossings count; shared endpoints are not crossing.
  const aH = isHorizontal(segA);
  const bH = isHorizontal(segB);
  if (aH === bH) return false;

  const h = aH ? segA : segB;
  const v = aH ? segB : segA;

  const hx1 = Math.min(h.x1, h.x2);
  const hx2 = Math.max(h.x1, h.x2);
  const hy = h.y1;

  const vy1 = Math.min(v.y1, v.y2);
  const vy2 = Math.max(v.y1, v.y2);
  const vx = v.x1;

  // strict interior intersection only (not at endpoints)
  const intersects = vx > hx1 && vx < hx2 && hy > vy1 && hy < vy2;
  return intersects;
}

export function bridgesCross(bridges) {
  const segs = [];
  for (const [key, count] of bridges.entries()) {
    if (!count) continue;
    segs.push(parseKey(key));
  }
  for (let i = 0; i < segs.length; i++) {
    for (let j = i + 1; j < segs.length; j++) {
      if (segmentsCross(segs[i], segs[j])) return true;
    }
  }
  return false;
}

export function computeCurrentCounts(islands, bridges) {
  const counts = new Map();
  for (const isl of islands) counts.set(isl.id, 0);

  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = parseKey(key);
    const a = islands.find((i) => i.x === x1 && i.y === y1);
    const b = islands.find((i) => i.x === x2 && i.y === y2);
    if (!a || !b) continue;
    counts.set(a.id, (counts.get(a.id) ?? 0) + n);
    counts.set(b.id, (counts.get(b.id) ?? 0) + n);
  }
  return counts;
}

export function checkConnectivity(islands, bridges) {
  if (islands.length === 0) return true;

  const adj = new Map();
  for (const isl of islands) adj.set(isl.id, []);

  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = parseKey(key);
    const a = islands.find((i) => i.x === x1 && i.y === y1);
    const b = islands.find((i) => i.x === x2 && i.y === y2);
    if (!a || !b) continue;
    // any positive bridge count implies connectivity edge
    adj.get(a.id).push(b.id);
    adj.get(b.id).push(a.id);
  }

  const start = islands[0].id;
  const seen = new Set([start]);
  const q = [start];
  while (q.length) {
    const cur = q.shift();
    for (const nxt of adj.get(cur) || []) {
      if (!seen.has(nxt)) {
        seen.add(nxt);
        q.push(nxt);
      }
    }
  }

  return seen.size === islands.length;
}

export function canAddBridge(islands, bridges, from, to, delta) {
  // delta is usually +1; can be negative if desired, but UI uses removal separately
  if (!areAdjacent(islands, from, to)) {
    return { valid: false, error: ERROR_NON_ADJACENT };
  }

  const key = canonicalBridgeKey(from, to);
  const cur = bridges.get(key) ?? 0;
  const next = cur + delta;

  if (next > 2) return { valid: false, error: ERROR_MAX_2 };
  if (next < 0) return { valid: false, error: ERROR_MAX_2 };

  // per-island counts cannot exceed value
  const counts = computeCurrentCounts(islands, bridges);
  const fromCur = counts.get(from.id) ?? 0;
  const toCur = counts.get(to.id) ?? 0;
  const fromNext = fromCur + delta;
  const toNext = toCur + delta;
  if (fromNext > from.value || toNext > to.value) {
    return { valid: false, error: ERROR_EXCEED };
  }

  // crossing check: test bridges with next state
  const tmp = new Map(bridges);
  if (next === 0) tmp.delete(key);
  else tmp.set(key, next);
  if (bridgesCross(tmp)) {
    return { valid: false, error: ERROR_CROSS };
  }

  return { valid: true, error: null };
}

export function isVictory(islands, bridges) {
  if (bridgesCross(bridges)) return false;
  const counts = computeCurrentCounts(islands, bridges);
  for (const isl of islands) {
    if ((counts.get(isl.id) ?? 0) !== isl.value) return false;
  }
  return checkConnectivity(islands, bridges);
}
EOF

cat > src/App.jsx <<'EOF'
import React, { useEffect, useMemo, useState } from 'react';
import { puzzles } from './data/puzzles';
import {
  canAddBridge,
  canonicalBridgeKey,
  isVictory,
} from './utils/hashiLogic';

const GRID = 40;
const SVG_W = 800;
const SVG_H = 600;

function toPx(n) {
  return n * GRID;
}

function islandById(islands, id) {
  return islands.find((i) => i.id === id) || null;
}

function bridgeKeyToPixels(key) {
  const [x1, y1, x2, y2] = key.split(',').map(Number);
  return {
    x1: toPx(x1),
    y1: toPx(y1),
    x2: toPx(x2),
    y2: toPx(y2),
  };
}

function computeKeyboardNeighbor(islands, from, dir) {
  // dir: 'left'|'right'|'up'|'down'
  const candidates = islands.filter((i) => i.id !== from.id);
  if (dir === 'left') {
    const sameRow = candidates.filter((i) => i.y === from.y && i.x < from.x);
    if (!sameRow.length) return null;
    return sameRow.reduce((best, cur) => (cur.x > best.x ? cur : best));
  }
  if (dir === 'right') {
    const sameRow = candidates.filter((i) => i.y === from.y && i.x > from.x);
    if (!sameRow.length) return null;
    return sameRow.reduce((best, cur) => (cur.x < best.x ? cur : best));
  }
  if (dir === 'up') {
    const sameCol = candidates.filter((i) => i.x === from.x && i.y < from.y);
    if (!sameCol.length) return null;
    return sameCol.reduce((best, cur) => (cur.y > best.y ? cur : best));
  }
  const sameCol = candidates.filter((i) => i.x === from.x && i.y > from.y);
  if (!sameCol.length) return null;
  return sameCol.reduce((best, cur) => (cur.y < best.y ? cur : best));
}

export default function App() {
  const [puzzleIndex, setPuzzleIndex] = useState(0);
  const [bridges, setBridges] = useState(() => new Map());
  const [selectedId, setSelectedId] = useState(null);
  const [cursorId, setCursorId] = useState(0);
  const [keyboardTargetId, setKeyboardTargetId] = useState(null);
  const [error, setError] = useState(null);

  const puzzle = puzzles[puzzleIndex];
  const islands = puzzle.islands;

  const victory = useMemo(() => isVictory(islands, bridges), [islands, bridges]);

  // Park cursor on island 0 on first load and any puzzle swap.
  useEffect(() => {
    setCursorId(0);
    setSelectedId(null);
    setKeyboardTargetId(null);
    setError(null);
    setBridges(new Map());
  }, [puzzleIndex]);

  function resetPuzzle() {
    setBridges(new Map());
    setSelectedId(null);
    setKeyboardTargetId(null);
    setError(null);
    setCursorId(0);
  }

  function applyBridgeToggle(from, to) {
    const key = canonicalBridgeKey(from, to);
    const cur = bridges.get(key) ?? 0;
    const next = cur === 0 ? 1 : cur === 1 ? 2 : 0;

    if (next === 0) {
      // always allowed to remove
      const nb = new Map(bridges);
      nb.delete(key);
      setBridges(nb);
      setSelectedId(null);
      setKeyboardTargetId(null);
      setError(null);
      setCursorId(0);
      return;
    }

    const delta = next - cur;
    const res = canAddBridge(islands, bridges, from, to, delta);
    if (!res.valid) {
      setError(res.error);
      return;
    }

    const nb = new Map(bridges);
    nb.set(key, next);
    setBridges(nb);
    setSelectedId(null);
    setKeyboardTargetId(null);
    setError(null);
    setCursorId(0);
  }

  function removeBridge(from, to) {
    const key = canonicalBridgeKey(from, to);
    if (!(bridges.get(key) ?? 0)) return;
    const nb = new Map(bridges);
    nb.delete(key);
    setBridges(nb);
    setSelectedId(null);
    setKeyboardTargetId(null);
    setError(null);
    setCursorId(0);
  }

  function onIslandClick(e, isl) {
    e.preventDefault();
    const curSelected = selectedId;
    if (curSelected == null) {
      setSelectedId(isl.id);
      return;
    }
    if (curSelected === isl.id) {
      setSelectedId(null);
      return;
    }
    const from = islandById(islands, curSelected);
    if (!from) {
      setSelectedId(null);
      return;
    }
    applyBridgeToggle(from, isl);
  }

  function onIslandContextMenu(e, isl) {
    e.preventDefault();
    // If an island is selected, right-click removes that bridge; otherwise no-op.
    if (selectedId == null || selectedId === isl.id) return;
    const from = islandById(islands, selectedId);
    if (!from) return;
    removeBridge(from, isl);
  }

  function onIslandMouseDown(e, isl) {
    // Ctrl+click removal.
    if (e.button === 0 && e.ctrlKey) {
      e.preventDefault();
      if (selectedId == null || selectedId === isl.id) return;
      const from = islandById(islands, selectedId);
      if (!from) return;
      removeBridge(from, isl);
    }
  }

  useEffect(() => {
    function onKeyDown(e) {
      const key = e.key;
      if (!['ArrowLeft', 'ArrowRight', 'ArrowUp', 'ArrowDown', 'Enter', 'Escape'].includes(key)) {
        return;
      }
      e.preventDefault();

      const cursor = islandById(islands, cursorId) || islands[0];
      if (!cursor) return;

      if (key === 'Escape') {
        setKeyboardTargetId(null);
        setSelectedId(null);
        setError(null);
        setCursorId(0);
        return;
      }

      if (key.startsWith('Arrow')) {
        const dir =
          key === 'ArrowLeft'
            ? 'left'
            : key === 'ArrowRight'
              ? 'right'
              : key === 'ArrowUp'
                ? 'up'
                : 'down';

        if (keyboardTargetId != null && selectedId != null) {
          const target = islandById(islands, keyboardTargetId);
          if (!target) return;
          const next = computeKeyboardNeighbor(islands, target, dir);
          if (next) setKeyboardTargetId(next.id);
          return;
        }

        const next = computeKeyboardNeighbor(islands, cursor, dir);
        if (next) setCursorId(next.id);
        return;
      }

      if (key === 'Enter') {
        if (selectedId == null) {
          setSelectedId(cursor.id);
          setKeyboardTargetId(cursor.id);
          return;
        }

        if (keyboardTargetId == null) {
          setKeyboardTargetId(cursor.id);
          return;
        }

        const from = islandById(islands, selectedId);
        const to = islandById(islands, keyboardTargetId);
        if (!from || !to) {
          setSelectedId(null);
          setKeyboardTargetId(null);
          return;
        }

        if (from.id === to.id) {
          // selecting same island again cancels selection
          setSelectedId(null);
          setKeyboardTargetId(null);
          return;
        }

        applyBridgeToggle(from, to);
      }
    }

    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, [bridges, cursorId, islands, keyboardTargetId, selectedId]);

  const bridgeLines = [];
  for (const [key, n] of bridges.entries()) {
    const { x1, y1, x2, y2 } = bridgeKeyToPixels(key);
    const horizontal = y1 === y2;
    const offset = 6; // px between double lines

    if (n === 1) {
      bridgeLines.push({ x1, y1, x2, y2 });
    } else if (n === 2) {
      if (horizontal) {
        bridgeLines.push({ x1, y1: y1 - offset, x2, y2: y2 - offset });
        bridgeLines.push({ x1, y1: y1 + offset, x2, y2: y2 + offset });
      } else {
        bridgeLines.push({ x1: x1 - offset, y1, x2: x2 - offset, y2 });
        bridgeLines.push({ x1: x1 + offset, y1, x2: x2 + offset, y2 });
      }
    }
  }

  const cursorIsland = islandById(islands, cursorId) || islands[0];
  const cursorX = cursorIsland ? toPx(cursorIsland.x) : 0;
  const cursorY = cursorIsland ? toPx(cursorIsland.y) : 0;

  return (
    <div style={{ width: '100vw', height: '100vh' }}>
      <div style={{ padding: '8px 10px' }}>
        <label>
          Puzzle:{' '}
          <select
            value={puzzleIndex}
            onChange={(e) => setPuzzleIndex(Number(e.target.value))}
            style={{
              background: 'black',
              color: '#0f0',
              border: '1px solid #0f0',
              fontFamily: 'monospace',
            }}
          >
            {puzzles.map((p, idx) => (
              <option key={p.id} value={idx}>
                {p.name}
              </option>
            ))}
          </select>
        </label>
        <button
          onClick={resetPuzzle}
          style={{
            marginLeft: 10,
            background: 'black',
            color: '#0f0',
            border: '1px solid #0f0',
            fontFamily: 'monospace',
            padding: '2px 8px',
            cursor: 'pointer',
          }}
        >
          Reset
        </button>
        {error ? <div className="error-message" style={{ marginTop: 6 }}>{error}</div> : null}
        {victory ? <div className="victory-banner" style={{ marginTop: 6 }}>SOLVED!</div> : null}
      </div>

      <svg
        width={SVG_W}
        height={SVG_H}
        style={{ display: 'block' }}
        viewBox={`0 0 ${SVG_W} ${SVG_H}`}
      >
        {/* bridges */}
        {bridgeLines.map((ln, idx) => (
          <line
            key={idx}
            x1={ln.x1}
            y1={ln.y1}
            x2={ln.x2}
            y2={ln.y2}
            stroke="#0f0"
            strokeWidth="4"
            strokeLinecap="round"
          />
        ))}

        {/* cursor (non-circle) */}
        {cursorIsland ? (
          <rect
            x={cursorX - 18}
            y={cursorY - 18}
            width={36}
            height={36}
            fill="none"
            stroke="#0f0"
            strokeWidth="2"
            strokeDasharray="4 3"
          />
        ) : null}

        {/* islands */}
        {islands.map((isl) => {
          const px = toPx(isl.x);
          const py = toPx(isl.y);
          const isSelected = selectedId === isl.id;
          return (
            <g
              key={isl.id}
              onClick={(e) => onIslandClick(e, isl)}
              onContextMenu={(e) => onIslandContextMenu(e, isl)}
              onMouseDown={(e) => onIslandMouseDown(e, isl)}
              style={{ cursor: 'pointer' }}
            >
              <circle
                cx={px}
                cy={py}
                r={16}
                fill="black"
                stroke="#0f0"
                strokeWidth={isSelected ? 4 : 2}
              />
              <text
                x={px}
                y={py + 5}
                textAnchor="middle"
                fontFamily="monospace"
                fontSize="16"
                fill="#0f0"
              >
                {isl.value}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
}
EOF

