          if (nxt) setKeyboardTargetId(nxt.id);
          return;
        }

        const nxt = computeKeyboardNeighbor(islands, cursor, dir);
        if (nxt) setCursorId(nxt.id);
        return;
      }

      if (e.key === 'Enter') {
        if (selectedId == null) {
          setSelectedId(cursor.id);
          setKeyboardTargetId(cursor.id);
          return;
        }

        if (keyboardTargetId == null) {
          setKeyboardTargetId(cursor.id);
          return;
        }

        const from = islandById(islands, selectedId);
        const to = islandById(islands, keyboardTargetId);
        if (!from || !to) {
          setSelectedId(null);
          setKeyboardTargetId(null);
          return;
        }

        if (from.id === to.id) {
          setSelectedId(null);
          setKeyboardTargetId(null);
          return;
        }

        applyBridgeToggle(from, to);
      }
    }

    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, [bridges, cursorId, islands, keyboardTargetId, selectedId]);

  // Expand bridge map into visible <line> elements only.
  const bridgeLines = [];
  for (const [key, n] of bridges.entries()) {
    const { x1, y1, x2, y2 } = bridgeKeyToPixels(key);
    const horizontal = y1 === y2;
    const offset = 6;

    if (n === 1) {
      bridgeLines.push({ x1, y1, x2, y2 });
    } else if (n === 2) {
      if (horizontal) {
        bridgeLines.push({ x1, y1: y1 - offset, x2, y2: y2 - offset });
        bridgeLines.push({ x1, y1: y1 + offset, x2, y2: y2 + offset });
      } else {
        bridgeLines.push({ x1: x1 - offset, y1, x2: x2 - offset, y2 });
        bridgeLines.push({ x1: x1 + offset, y1, x2: x2 + offset, y2 });
      }
    }
  }

  const cursorIsland = islandById(islands, cursorId) || islands[0];
  const cursorX = cursorIsland ? px(cursorIsland.x) : 0;
  const cursorY = cursorIsland ? px(cursorIsland.y) : 0;

  return (
    <div style={{ width: '100vw', height: '100vh', position: 'relative' }}>
      {/* Controls overlay: does not move the SVG origin (0,0). */}
      <div style={{ position: 'absolute', left: 0, top: 0, padding: '8px 10px', zIndex: 2 }}>
        <label>
          Puzzle:{' '}
          <select
            value={puzzleIndex}
            onChange={(e) => setPuzzleIndex(Number(e.target.value))}
            style={{
              background: 'black',
              color: '#0f0',
              border: '1px solid #0f0',
              fontFamily: 'monospace',
            }}
          >
            {puzzles.map((p, idx) => (
              <option key={p.id} value={idx}>
                {p.name}
              </option>
            ))}
          </select>
        </label>
        <button
          onClick={resetPuzzle}
          style={{
            marginLeft: 10,
            background: 'black',
            color: '#0f0',
            border: '1px solid #0f0',
            fontFamily: 'monospace',
            padding: '2px 8px',
            cursor: 'pointer',
          }}
        >
          Reset
        </button>
        {error ? (
          <div className="error-message" style={{ marginTop: 6 }}>
            {error}
          </div>
        ) : null}
        {victory ? (
          <div className="victory-banner" style={{ marginTop: 6 }}>
            SOLVED!
          </div>
        ) : null}
      </div>

      <svg
        width={SVG_W}
        height={SVG_H}
        viewBox={`0 0 ${SVG_W} ${SVG_H}`}
        style={{ position: 'absolute', left: 0, top: 0, display: 'block', zIndex: 1 }}
      >
        {bridgeLines.map((ln, idx) => (
          <line
            key={idx}
            x1={ln.x1}
            y1={ln.y1}
            x2={ln.x2}
            y2={ln.y2}
            stroke="#0f0"
            strokeWidth="4"
            strokeLinecap="round"
          />
        ))}

        {/* Cursor must not be a circle */}
        {cursorIsland ? (
          <rect
            x={cursorX - 18}
            y={cursorY - 18}
            width={36}
            height={36}
            fill="none"
            stroke="#0f0"
            strokeWidth="2"
            strokeDasharray="4 3"
          />
        ) : null}

        {islands.map((isl) => {
          const x = px(isl.x);
          const y = px(isl.y);
          const isSelected = selectedId === isl.id;
          return (
            <g
              key={isl.id}
              onClick={(e) => onIslandClick(e, isl)}
              onContextMenu={(e) => onIslandContextMenu(e, isl)}
              onMouseDown={(e) => onIslandMouseDown(e, isl)}
              style={{ cursor: 'pointer' }}
            >
              <circle
                cx={x}
                cy={y}
                r={16}
                fill="black"
                stroke="#0f0"
                strokeWidth={isSelected ? 4 : 2}
              />
              <text
                x={x}
                y={y + 5}
                textAnchor="middle"
                fontFamily="monospace"
                fontSize="16"
                fill="#0f0"
              >
                {isl.value}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
}
